EXISTS (`GetRandomData operation DA`) {
  EXISTS (`variable read USE`) {
    EXISTS (`PredictableSeedExpr SOURCE`) {
      AND {
        (`DA's qualifier is USE`),
        EXISTS (`expression ARG`) {
          AND {
            OR {
              EXISTS (`expression E`, `VariableAssign DEF`) {
                AND {
                  (`DEF's source expression is E`),
                  EXISTS (`ClassInstanceExpr C`) {
                    (`E is C, C's constructed type is SecureRandom, C has exactly 1 argument, C's argument 0 is ARG`)
                  },
                  OR {
                    (`DEF and USE are a def-use pair`),
                    EXISTS (`Field F`) {
                      AND {
                        (`DEF's destination variable is F`),
                        (`USE is an access to F`)
                      }
                    }
                  }
                }
              },
              EXISTS (`MethodCall MC`, `variable read SEEDUSE`) {
                AND {
                  (`MC's qualifier is SEEDUSE`),
                  EXISTS (`Method M`) {
                    (`MC's called method is M, M's declaring type is SecureRandom, M's name is "setSeed", MC's argument 0 is ARG`)
                  },
                  (`SEEDUSE and USE are a use-use pair`)
                }
              }
            },
            (`there is a data flow from SOURCE's expression node to ARG's expression node`)
          }
        },
        NOT {
          OR {
            EXISTS (`expression ARG2`) {
              AND {
                OR {
                  EXISTS (`expression E2`, `VariableAssign DEF2`) {
                    AND {
                      (`DEF2's source expression is E2`),
                      EXISTS (`ClassInstanceExpr C2`) {
                        (`E2 is C2, C2's constructed type is SecureRandom, C2 has exactly 1 argument, C2's argument 0 is ARG2`)
                      },
                      OR {
                        (`DEF2 and USE are a def-use pair`),
                        EXISTS (`Field F2`) {
                          AND {
                            (`DEF2's destination variable is F2`),
                            (`USE is an access to F2`)
                          }
                        }
                      }
                    }
                  },
                  EXISTS (`MethodCall MC2`, `variable read SEEDUSE2`) {
                    AND {
                      (`MC2's qualifier is SEEDUSE2`),
                      EXISTS (`Method M2`) {
                        (`MC2's called method is M2, M2's declaring type is SecureRandom, M2's name is "setSeed", MC2's argument 0 is ARG2`)
                      },
                      (`SEEDUSE2 and USE are a use-use pair`)
                    }
                  }
                },
                NOT { (`there exists a predictable seed flow to ARG2`) }
              }
            },
            EXISTS (`GetRandomData operation DA2`, `variable read SEEDUSE3`) {
              AND {
                (`DA2's qualifier is SEEDUSE3`),
                (`SEEDUSE3 and USE are a use-use pair`),
                NOT {
                  EXISTS (`variable read PRIOR`) {
                    AND {
                      (`PRIOR and SEEDUSE3 are a use-use pair`),
                      OR {
                        EXISTS (`expression ARG3`) {
                          OR {
                            EXISTS (`expression E3`, `VariableAssign DEF3`) {
                              AND {
                                (`DEF3's source expression is E3`),
                                EXISTS (`ClassInstanceExpr C3`) {
                                  (`E3 is C3, C3's constructed type is SecureRandom, C3 has exactly 1 argument, C3's argument 0 is ARG3`)
                                },
                                OR {
                                  (`DEF3 and PRIOR are a def-use pair`),
                                  EXISTS (`Field F3`) {
                                    AND {
                                      (`DEF3's destination variable is F3`),
                                      (`PRIOR is an access to F3`)
                                    }
                                  }
                                }
                              }
                            },
                            EXISTS (`MethodCall MC3`, `variable read SEEDUSE4`) {
                              AND {
                                (`MC3's qualifier is SEEDUSE4`),
                                EXISTS (`Method M3`) {
                                  (`MC3's called method is M3, M3's declaring type is SecureRandom, M3's name is "setSeed", MC3's argument 0 is ARG3`)
                                },
                                (`SEEDUSE4 and PRIOR are a use-use pair`)
                              }
                            }
                          }
                        },
                        EXISTS (`GetRandomData operation DA3`, `variable read SEEDUSE5`) {
                          AND {
                            (`DA3's qualifier is SEEDUSE5`),
                            (`SEEDUSE5 and PRIOR are a use-use pair`)
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
